export const saveQuickLink=l=>{const e=Object.assign({label:"",icon:"",linkUrl:""},l),i=validateQuicklinkParams(e);return i?Promise.reject(new Error(i)):globalRequest.post(buildUrl("save-quicklink"),buildQuicklinkModel(e))};export const removeQuickLink=(l,e)=>globalRequest.post(buildUrl("remove-quicklink"),{pageUrl:l,pageLabel:e});const buildQuicklinkModel=l=>({PageLabel:l.label,PageUrl:l.linkUrl,PageIcon:l.icon}),validateQuicklinkParams=l=>{let e="";const i=[];return""==l.label&&i.push("- Page label not found."),""===l.icon&&i.push("- Icon not found."),""==l.linkUrl&&i.push("- Page url not found."),i.length>0&&(e=i.join("<br />")),e},buildUrl=l=>`${window.location.origin}/start/${l}`;